module RefModule (
    input clk,
    input reset,
    input req1,
    input req2,
    output reg busy,
    output reg ack1,
    output reg ack2
);

    reg pipeline_reg;

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            busy <= 0;
            ack1 <= 0;
            ack2 <= 0;
            pipeline_reg <= 0;
        end else begin
            case (pipeline_reg)
                0: begin // Idle pipeline_reg
                    if (req1) begin
                        busy <= 1;
                        ack1 <= 1;
                        ack2 <= 0;
                        pipeline_reg <= 1;
                    end else if (req2) begin
                        busy <= 1;
                        ack1 <= 0;
                        ack2 <= 1;
                        pipeline_reg <= 2;
                    end
                end
                1: begin // Processing req1
                    if (ack1) begin
                        ack1 <= 0; // Acknowledge req1
                        busy <= 0; // Go back to idle
                        pipeline_reg <= 0;
                    end
                end
                2: begin // Processing req2
                    if (ack2) begin
                        ack2 <= 0; // Acknowledge req2
                        busy <= 0; // Go back to idle
                        pipeline_reg <= 0;
                    end
                end
            endcase
        end
    end
endmodule
